+describe("google thinking policy", () => {
+  it.each([
+    ["off", "LOW"],
+    ["minimal", "LOW"],
+    ["low", "LOW"],
+    ["medium", "HIGH"],
+    ["adaptive", "HIGH"],
+    ["high", "HIGH"],
+    ["xhigh", "HIGH"],
+  ] as const)("maps Gemini 3 Pro thinking level %s to %s", (thinkingLevel, expected) => {
+    expect(
+      resolveGoogleGemini3ThinkingLevel({
+        modelId: "gemini-3.1-pro-preview",
+        thinkingLevel,
+      }),
+    ).toBe(expected);
+  });
+
+  it.each([
+    [0, "LOW"],
+    [2048, "LOW"],
+    [2049, "HIGH"],
+  ] as const)("maps Gemini 3 Pro budget %s to %s", (thinkingBudget, expected) => {
+    expect(
+      resolveGoogleGemini3ThinkingLevel({
+        modelId: "gemini-pro-latest",
+        thinkingBudget,
+      }),
+    ).toBe(expected);
+  });
+
+  it.each([
+    ["off", "MINIMAL"],
+    ["minimal", "MINIMAL"],
+    ["low", "LOW"],
+    ["medium", "MEDIUM"],
+    ["adaptive", "MEDIUM"],
+    ["high", "HIGH"],
+    ["xhigh", "HIGH"],
+  ] as const)("maps Gemini 3 Flash thinking level %s to %s", (thinkingLevel, expected) => {
+    expect(
+      resolveGoogleGemini3ThinkingLevel({
+        modelId: "gemini-flash-latest",
+        thinkingLevel,
+      }),
+    ).toBe(expected);
+  });
+
+  it.each([
+    [-1, "MINIMAL"],
+    [0, "MINIMAL"],
+    [2048, "LOW"],
+    [8192, "MEDIUM"],
+    [8193, "HIGH"],
+  ] as const)("maps Gemini 3 Flash budget %s to %s", (thinkingBudget, expected) => {
+    expect(
+      resolveGoogleGemini3ThinkingLevel({
+        modelId: "gemini-3.1-flash-lite-preview",
+        thinkingBudget,
+      }),
+    ).toBe(expected);
+  });
+
+  it("removes thinkingBudget=0 for Gemini 2.5 Pro", () => {
+    const payload = {
+      config: {
+        thinkingConfig: { thinkingBudget: 0 },
+      },
+    };
